import os
import langfuse
from langfuse import observe

# Read run-id from environment
run_id = os.environ.get("ZEALT_RUN_ID", "default")

# Define identifiers
session_id = f"obs-deco-session-{run_id}"
user_id = f"obs-deco-user-{run_id}"
tags = ["obs-decorator", f"harbor-{run_id}"]

@observe(as_type="generation")
def call_llm(prompt):
    # Simulate an LLM call
    # In some versions, observe might support setting attributes via return or context
    # Try to set model via observe decorator if possible, but here we just return
    # and let the decorator handle the rest.
    # To be safe, we can use the langfuse client if needed, but the requirement says @observe
    return "This is a simulated response from the LLM."

@observe()
def run_pipeline(user_query):
    # Try to set attributes via langfuse.langfuse_context if it exists, 
    # or by other means if not.
    try:
        from langfuse.decorators import langfuse_context
        langfuse_context.update_current_trace(
            user_id=user_id,
            session_id=session_id,
            tags=tags
        )
    except ImportError:
        # Fallback if langfuse_context is not in .decorators
        try:
            from langfuse import langfuse_context
            langfuse_context.update_current_trace(
                user_id=user_id,
                session_id=session_id,
                tags=tags
            )
        except ImportError:
            # If langfuse_context is not available, we might need to use the client or other helpers
            pass

    # Nested call
    response = call_llm(user_query)

    # Get current trace id
    try:
        from langfuse.decorators import langfuse_context
        return langfuse_context.get_current_trace_id()
    except ImportError:
        try:
            from langfuse import langfuse_context
            return langfuse_context.get_current_trace_id()
        except ImportError:
            return "unknown"

if __name__ == "__main__":
    # Execute pipeline
    trace_id = run_pipeline("What is the weather today?")

    # Force delivery of events
    try:
        from langfuse.decorators import langfuse_context
        langfuse_context.flush()
    except ImportError:
        try:
            from langfuse import langfuse_context
            langfuse_context.flush()
        except ImportError:
            pass

    # Write trace id to log file
    log_file_path = "/home/user/myproject/output.log"
    with open(log_file_path, "w") as f:
        f.write(f"Trace ID: {trace_id}\n")

    print(f"Pipeline executed successfully. Trace ID: {trace_id}")

